const copyText = (text) => {
  try { if (navigator.clipboard && navigator.clipboard.writeText) { navigator.clipboard.writeText(text); return true; } } catch (e) {}
  try { const ta = document.createElement("textarea"); ta.value = text; ta.style.position = "fixed"; ta.style.opacity = "0"; document.body.appendChild(ta); ta.select(); document.execCommand("copy"); document.body.removeChild(ta); return true; } catch (e) { return false; }
};
const shareLink = async (title, text, url) => {
  try { if (navigator.share) { await navigator.share({ title, text, url }); return "shared"; } } catch (e) { if (e && e.name === "AbortError") return "aborted"; }
  return copyText(url) ? "copied" : "fail";
};
