const periodRange = (opt, de, ate) => {
  const base = new Date(today() + "T12:00:00"); const y = base.getFullYear(), m = base.getMonth(); const mk = (dt) => isoOf(dt); const DAY = 86400000;
  if (opt === "Hoje") return { from: today(), to: today() };
  if (opt === "Este mês") return { from: mk(new Date(y, m, 1)), to: mk(new Date(y, m + 1, 0)) };
  if (opt === "Mês passado") return { from: mk(new Date(y, m - 1, 1)), to: mk(new Date(y, m, 0)) };
  if (opt === "7 dias") return { from: mk(new Date(base.getTime() - 6 * DAY)), to: today() };
  if (opt === "30 dias") return { from: mk(new Date(base.getTime() - 29 * DAY)), to: today() };
  if (opt === "90 dias") return { from: mk(new Date(base.getTime() - 89 * DAY)), to: today() };
  if (opt === "Período") return { from: de || today(), to: ate || today() };
  return { from: today(), to: today() };
};
const prevOf = (r) => { const DAY = 86400000; const f = new Date(r.from + "T12:00:00"), tt = new Date(r.to + "T12:00:00"); const L = Math.round((tt - f) / DAY) + 1; const pTo = new Date(f.getTime() - DAY); const pFrom = new Date(pTo.getTime() - (L - 1) * DAY); return { from: isoOf(pFrom), to: isoOf(pTo) }; };
const ddmm = (v) => (v || "").split("-").reverse().slice(0, 2).join("/");
const onlyDigits = (s) => (s || "").replace(/\D/g, "");
const maskPhone = (s) => { const d = onlyDigits(s).slice(0, 11); if (d.length <= 10) return d.replace(/^(\d{2})(\d)/, "($1) $2").replace(/(\d{4})(\d)/, "$1-$2"); return d.replace(/^(\d{2})(\d)/, "($1) $2").replace(/(\d{5})(\d)/, "$1-$2"); };
const maskCPF = (s) => onlyDigits(s).slice(0, 11).replace(/(\d{3})(\d)/, "$1.$2").replace(/(\d{3})(\d)/, "$1.$2").replace(/(\d{3})(\d{1,2})$/, "$1-$2");
const maskCNPJ = (s) => onlyDigits(s).slice(0, 14).replace(/^(\d{2})(\d)/, "$1.$2").replace(/(\d{3})(\d)/, "$1.$2").replace(/(\d{3})(\d)/, "$1/$2").replace(/(\d{4})(\d{1,2})$/, "$1-$2");
const validEmail = (s) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(s || "");
