function MonthCal({ monthDate, start, end, onPick }) {
  const t = useT(); const y = monthDate.getFullYear(), m = monthDate.getMonth();
  const lead = new Date(y, m, 1).getDay(); const days = new Date(y, m + 1, 0).getDate();
  const iso = (d) => isoOf(new Date(y, m, d)); const cells = [];
  for (let i = 0; i < lead; i++) cells.push(null);
  for (let d = 1; d <= days; d++) cells.push(d);
  const inR = (d) => { const v = iso(d); return start && end && v > start && v < end; };
  const isEnd = (d) => { const v = iso(d); return v === start || v === end; };
  return <div style={{ flex: "1 1 240px", minWidth: 230 }}>
    <div style={{ textAlign: "center", fontSize: 14, fontWeight: 700, color: t.text, marginBottom: 10, textTransform: "capitalize" }}>{MESES[m]} {y}</div>
    <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 2, textAlign: "center", fontSize: 11, color: t.textSec, marginBottom: 4 }}>{["dom", "seg", "ter", "qua", "qui", "sex", "sab"].map((w, i) => <div key={i}>{w}</div>)}</div>
    <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 2 }}>{cells.map((d, i) => d === null ? <div key={i} /> : <button key={i} onClick={() => onPick(iso(d))} style={{ height: 34, borderRadius: 9, border: "none", cursor: "pointer", fontFamily: FONT, fontSize: 12.5, fontWeight: 600, background: isEnd(d) ? PALETTE.sage : inR(d) ? "rgba(124,143,115,0.28)" : "transparent", color: isEnd(d) ? "#fff" : t.text }}>{d}</button>)}</div>
  </div>;
}
function RangePickerModal({ open, onClose, from, to, onApply }) {
  const t = useT();
  const [start, setStart] = useState(from); const [end, setEnd] = useState(to);
  const [view, setView] = useState(new Date(today() + "T12:00:00"));
  useEffect(() => { if (open) { setStart(from); setEnd(to); setView(new Date((from || today()) + "T12:00:00")); } }, [open]);
  if (!open) return null;
  const pick = (v) => { if (!start || (start && end)) { setStart(v); setEnd(null); } else { if (v < start) setStart(v); else setEnd(v); } };
  const nextMonth = new Date(view.getFullYear(), view.getMonth() + 1, 1);
  const apply = () => { onApply({ from: start, to: end || start }); onClose(); };
  return <Modal open={open} onClose={onClose} title="Selecionar período" icon={Calendar} width={640} footer={<><GhostBtn onClick={onClose}>Cancelar</GhostBtn><PrimaryBtn onClick={apply} disabled={!start}>Aplicar</PrimaryBtn></>}>
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
      <button onClick={() => setView(new Date(view.getFullYear(), view.getMonth() - 1, 1))} style={miniBtn(t)}><ChevronLeft size={15} /></button>
      <span style={{ fontSize: 12.5, color: t.textSec }}>{start ? (end ? `${ddmm(start)} – ${ddmm(end)}` : `${ddmm(start)} — escolha a data final`) : "Escolha a data inicial"}</span>
      <button onClick={() => setView(new Date(view.getFullYear(), view.getMonth() + 1, 1))} style={miniBtn(t)}><ChevronRight size={15} /></button>
    </div>
    <div style={{ display: "flex", gap: 24, flexWrap: "wrap", justifyContent: "center" }}>
      <MonthCal monthDate={view} start={start} end={end} onPick={pick} />
      <MonthCal monthDate={nextMonth} start={start} end={end} onPick={pick} />
    </div>
  </Modal>;
}
function PeriodFilter({ value, onChange }) {
  const t = useT();
  const opts = ["Hoje", "Este mês", "Mês passado", "7 dias", "30 dias", "90 dias"];
  const [sel, setSel] = useState(value || "Este mês");
  const [de, setDe] = useState(today()); const [ate, setAte] = useState(today());
  const [open, setOpen] = useState(false);
  const range = periodRange(sel, de, ate);
  useEffect(() => { onChange && onChange(range); }, [sel, de, ate]);
  const pill = (active) => ({ height: 34, padding: "0 14px", borderRadius: 999, border: `1px solid ${active ? "transparent" : t.border}`, boxSizing: "border-box", display: "inline-flex", alignItems: "center", gap: 5, fontSize: 13, fontWeight: 600, lineHeight: 1, cursor: "pointer", fontFamily: FONT, background: active ? PALETTE.sage : t.card, color: active ? "#fff" : t.textSec, whiteSpace: "nowrap" });
  return <div className="bloomio-period" style={{ display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center" }}>
    {opts.map((o) => <button key={o} onClick={() => setSel(o)} style={pill(sel === o)}>{o}</button>)}
    <button onClick={() => { setSel("Período"); setOpen(true); }} style={pill(sel === "Período")}><Calendar size={13} /> Período</button>
    <span style={{ display: "inline-flex", alignItems: "center", height: 34 }}><Badge variant="outline">{range.from === range.to ? ddmm(range.from) : `${ddmm(range.from)} – ${ddmm(range.to)}`}</Badge></span>
    <RangePickerModal open={open} onClose={() => setOpen(false)} from={de} to={ate} onApply={(r) => { setDe(r.from); setAte(r.to); setSel("Período"); }} />
  </div>;
}
