function QRModal({ open, onClose, url, title }) {
  const t = useT(); const toast = useToast();
  const mat = useMemo(() => { if (!open || !url) return null; try { return QR.matrix(url); } catch (e) { return null; } }, [open, url]);
  if (!open) return null;
  const n = mat ? mat.length : 0; const quiet = 2; const total = n + quiet * 2; const px = 240; const cell = px / total;
  const baixar = () => {
    if (!mat) return;
    const c = document.createElement("canvas"); c.width = px; c.height = px; const g = c.getContext("2d");
    g.fillStyle = "#fff"; g.fillRect(0, 0, px, px); g.fillStyle = "#182035";
    for (let r = 0; r < n; r++) for (let col = 0; col < n; col++) if (mat[r][col]) g.fillRect((col + quiet) * cell, (r + quiet) * cell, cell + 0.5, cell + 0.5);
    const a = document.createElement("a"); a.href = c.toDataURL("image/png"); a.download = "qrcode-bloomio.png"; a.click(); toast("QR Code baixado!");
  };
  return <Modal open={open} onClose={onClose} title="QR Code" icon={Box} width={360} footer={<><GhostBtn onClick={() => { copyText(url); toast("Link copiado!"); }}><Copy size={14} /> Copiar link</GhostBtn><PrimaryBtn onClick={baixar}><Send size={15} /> Baixar PNG</PrimaryBtn></>}>
    <p style={{ fontSize: 13, color: t.textSec, margin: "0 0 14px", textAlign: "center" }}>{title || "Aponte a câmera para agendar"}</p>
    <div style={{ display: "flex", justifyContent: "center" }}>
      {mat ? <div style={{ background: "#fff", padding: 12, borderRadius: 14, border: `1px solid ${t.border}` }}>
        <svg width={px} height={px} viewBox={`0 0 ${total} ${total}`} shapeRendering="crispEdges">
          <rect width={total} height={total} fill="#fff" />
          {mat.map((row, r) => row.map((dark, c) => dark ? <rect key={r + "-" + c} x={c + quiet} y={r + quiet} width={1} height={1} fill="#182035" /> : null))}
        </svg>
      </div> : <div style={{ fontSize: 13, color: t.textSec, padding: "30px 0" }}>Não foi possível gerar o QR.</div>}
    </div>
    <div style={{ fontSize: 12, color: t.textSec, textAlign: "center", marginTop: 12, wordBreak: "break-all" }}>{url}</div>
  </Modal>;
}
