async function callClaude(messages, system) {
  // Em produção (Vite), usa o proxy seguro do backend; no preview/demo, chama direto.
  const API_URL = (typeof import.meta !== "undefined" && import.meta.env && import.meta.env.VITE_API_URL) || "";
  if (API_URL) {
    let token = "";
    try { const raw = window.localStorage.getItem("bloomio_token"); if (raw) token = raw; } catch (e) {}
    const r = await fetch(`${API_URL}/ai/gerar`, { method: "POST", headers: { "Content-Type": "application/json", ...(token ? { Authorization: `Bearer ${token}` } : {}) }, body: JSON.stringify({ system, messages, max_tokens: 1000 }) });
    const d = await r.json();
    return (d.text || "").trim();
  }
  const res = await fetch("https://api.anthropic.com/v1/messages", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 1000, system, messages }) });
  const data = await res.json();
  return (data.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n").trim();
}

