function MiniCalendar({ refDate, onPick }) {
  const t = useT();
  const [vm, setVm] = useState(new Date(refDate.getFullYear(), refDate.getMonth(), 1));
  useEffect(() => { setVm(new Date(refDate.getFullYear(), refDate.getMonth(), 1)); }, [refDate]);
  const y = vm.getFullYear(), m = vm.getMonth();
  const firstWd = (new Date(y, m, 1).getDay() + 6) % 7;
  const daysIn = new Date(y, m + 1, 0).getDate();
  const cells = []; for (let i = 0; i < firstWd; i++) cells.push(null); for (let d = 1; d <= daysIn; d++) cells.push(d);
  const todayStr = nowBR().toDateString();
  const MN = ["JANEIRO", "FEVEREIRO", "MARÇO", "ABRIL", "MAIO", "JUNHO", "JULHO", "AGOSTO", "SETEMBRO", "OUTUBRO", "NOVEMBRO", "DEZEMBRO"];
  return <div><div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}><button style={navBtn(t)} onClick={() => setVm(new Date(y, m - 1, 1))}><ChevronLeft size={14} /></button><span style={{ fontSize: 12.5, fontWeight: 700, color: t.text }}>{MN[m]} {y}</span><button style={navBtn(t)} onClick={() => setVm(new Date(y, m + 1, 1))}><ChevronRight size={14} /></button></div>
    <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 2, textAlign: "center" }}>{["S", "T", "Q", "Q", "S", "S", "D"].map((d, i) => <div key={i} style={{ fontSize: 11, fontWeight: 600, color: t.textSec, padding: "3px 0" }}>{d}</div>)}
      {cells.map((d, i) => { if (d === null) return <div key={i} />; const date = new Date(y, m, d); const sel = date.toDateString() === refDate.toDateString(); const tdy = date.toDateString() === todayStr; return <div key={i} onClick={() => onPick(date)} style={{ fontSize: 12, padding: "5px 0", borderRadius: 7, color: sel ? "#fff" : t.text, background: sel ? PALETTE.sage : "transparent", border: tdy && !sel ? `1px solid ${t.sage}` : "1px solid transparent", cursor: "pointer", fontWeight: sel || tdy ? 700 : 400 }}>{d}</div>; })}</div></div>;
}
