  const rec = transactions.filter((x) => x.type === "receita" && inRange(x.date)); const desp = transactions.filter((x) => x.type === "despesa" && inRange(x.date));
  const apptsR = appointments.filter((a) => inRange(a.date)); const salesR = sales.filter((s) => inRange(s.date));
  const totalR = rec.reduce((a, x) => a + x.amount, 0); const totalD = desp.reduce((a, x) => a + x.amount, 0);
  const concl = apptsR.filter((a) => a.status === "concluido").length;
  const taxa = apptsR.length ? Math.round((concl / apptsR.length) * 100) : 0;
  const agg = (arr, key) => { const m = {}; arr.forEach((x) => { const k = x[key]; m[k] = (m[k] || 0) + (x.amount || 1); }); return Object.entries(m).map(([n, v]) => ({ n, v })); };
  const catData = agg(rec, "category"); const payData = agg(rec, "method");
  const statusMap = {}; apptsR.forEach((a) => { statusMap[a.status] = (statusMap[a.status] || 0) + 1; });
  const statusData = Object.entries(statusMap).map(([n, v]) => ({ n, v }));
  const rxd = [{ n: "Receita", v: totalR }, { n: "Despesa", v: totalD }];
  const svcCount = {}; salesR.forEach((s) => s.items.forEach((it) => { svcCount[it.name] = (svcCount[it.name] || 0) + it.qty; }));
  const svcRank = Object.entries(svcCount).map(([n, v]) => ({ n, v })).sort((a, b) => b.v - a.v);
  const proRank = professionals.map((p) => { const ss = salesR.filter((s) => s.professionalId === p.id); return { name: p.name, vendas: ss.length, receita: ss.reduce((a, s) => a + s.total, 0) }; }).filter((x) => x.vendas > 0).sort((a, b) => b.receita - a.receita);
  const COLZ = [PALETTE.sage, PALETTE.navy, PALETTE.info, PALETTE.warning, PALETTE.error];
