  const chartCard = (title, sub, has, children) => <Card style={{ padding: 20 }}><h3 style={{ fontSize: 15, fontWeight: 700, color: t.text, margin: "0 0 2px" }}>{title}</h3><p style={{ fontSize: 12.5, color: t.textSec, margin: "0 0 14px" }}>{sub}</p>{has ? children : empty}</Card>;
  const pie = (data) => <ResponsiveContainer width="100%" height={210}><PieChart><Pie data={data} dataKey="v" nameKey="n" cx="50%" cy="50%" innerRadius={45} outerRadius={78} paddingAngle={3}>{data.map((e, i) => <Cell key={i} fill={COLZ[i % COLZ.length]} />)}</Pie><Tooltip contentStyle={{ borderRadius: 10, fontSize: 12, fontFamily: FONT }} /><Legend wrapperStyle={{ fontSize: 12 }} /></PieChart></ResponsiveContainer>;
