      {msgs.map((m, i) => <div key={i} style={{ display: "flex", justifyContent: m.role === "user" ? "flex-end" : "flex-start" }}><div style={{ maxWidth: "78%", padding: "11px 15px", borderRadius: 14, fontSize: 13.5, lineHeight: 1.6, whiteSpace: "pre-wrap", background: m.role === "user" ? PALETTE.navy : t.bg, color: m.role === "user" ? "#fff" : t.text, border: m.role === "user" ? "none" : `1px solid ${t.border}` }}>{m.content}</div></div>)}
