function EditableList({ items, onChange, placeholder, defaults }) {
  const t = useT(); const [val, setVal] = useState("");
  const add = () => { if (val.trim()) { onChange([...items, val.trim()]); setVal(""); } };
  return <div>
    <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>{items.map((it, i) => <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, padding: "9px 13px", borderRadius: 10, border: `1px solid ${t.border}` }}><span style={{ flex: 1, fontSize: 13.5, color: t.text }}>{it}</span><button onClick={() => onChange(items.filter((_, j) => j !== i))} style={{ background: "none", border: "none", cursor: "pointer", color: t.textSec }}><Trash2 size={14} /></button></div>)}</div>
    <div style={{ display: "flex", gap: 8, marginTop: 8 }}><Input value={val} onChange={(e) => setVal(e.target.value)} onKeyDown={(e) => e.key === "Enter" && add()} placeholder={placeholder} /><GhostBtn onClick={add}><Plus size={14} /> Adicionar</GhostBtn></div>
    <button onClick={() => onChange([...defaults])} style={{ background: "none", border: "none", color: t.sage, fontSize: 12.5, fontWeight: 600, cursor: "pointer", fontFamily: FONT, marginTop: 8 }}>Restaurar padrão</button>
  </div>;
}
