/* ===== PDV ===== */
function PDV({ open, onClose }) {
  const t = useT(); const toast = useToast(); const { services, products, clients, professionals, addSale, openModal, settings } = useData();
  const [catTab, setCatTab] = useState("Serviços"); const [q, setQ] = useState("");
  const pays = settings.finance.paymentMethods;
  const [cart, setCart] = useState([]); const [proId, setProId] = useState(""); const [cliId, setCliId] = useState(""); const [discount, setDiscount] = useState(""); const [pay, setPay] = useState(pays[0] || "PIX");
  useEffect(() => { if (!open) { setCart([]); setQ(""); setProId(""); setCliId(""); setDiscount(""); setPay("PIX"); } }, [open]);
  const items = catTab === "Serviços" ? services : products;
  const filtered = items.filter((i) => i.name.toLowerCase().includes(q.toLowerCase()));
  const add = (i) => setCart((c) => { const ex = c.find((x) => x.id === i.id); return ex ? c.map((x) => x.id === i.id ? { ...x, qty: x.qty + 1 } : x) : [...c, { id: i.id, name: i.name, price: i.price || 0, qty: 1 }]; });
  const subtotal = cart.reduce((s, c) => s + c.price * c.qty, 0);
  const total = Math.max(0, subtotal - (+discount || 0));
  const finalize = () => { addSale({ items: cart, subtotal, discount: +discount || 0, total, payment: pay, professionalId: proId || null, clientId: cliId || null }); const cli = clients.find((c) => c.id === cliId); const pro = professionals.find((p) => p.id === proId); const rows = cart.map((c) => `<tr><td>${c.name} × ${c.qty}</td><td class="right">${brl(c.price * c.qty)}</td></tr>`).join(""); printDoc("Comprovante de Venda", `<h1>Comprovante de Venda</h1><div class="muted">Emitido em ${new Date().toLocaleString("pt-BR")} · Forma de pagamento: ${pay}</div>${cli || pro ? `<div class="muted" style="margin-top:6px">${cli ? "Cliente: " + cli.name : ""}${cli && pro ? " · " : ""}${pro ? "Profissional: " + pro.name : ""}</div>` : ""}<table style="margin-top:14px"><tr><th>Item</th><th class="right">Valor</th></tr>${rows}<tr><td>Subtotal</td><td class="right">${brl(subtotal)}</td></tr>${(+discount || 0) > 0 ? `<tr><td>Desconto</td><td class="right">− ${brl(+discount || 0)}</td></tr>` : ""}</table><div class="tot right">Total: ${brl(total)}</div><p class="muted" style="margin-top:16px">Obrigado pela preferência!</p>`, "Comprovante de Venda", estHead(settings.establishment)); toast(`Venda de ${brl(total)} registrada!`); onClose(); };
  return <Modal open={open} onClose={onClose} title="Nova Venda (PDV)" icon={ShoppingCart} fullscreen footer={null} bodyBg={t.bg}>
    <div className="bloomio-side" style={{ display: "grid", gridTemplateColumns: "1fr 380px", gap: 22 }}>
      <div>
        <div style={{ maxWidth: 280 }}><Tabs tabs={["Serviços", "Produtos"]} active={catTab} onChange={setCatTab} /></div>
        <SearchBar placeholder={`Buscar ${catTab.toLowerCase()}...`} value={q} onChange={(e) => setQ(e.target.value)} />
        <div style={{ marginTop: 12, display: "flex", flexDirection: "column", gap: 7, maxHeight: "52vh", overflowY: "auto" }}>
          {filtered.length === 0 ? <div style={{ fontSize: 13.5, color: t.textSec, textAlign: "center", padding: "30px 0" }}>Nenhum {catTab === "Serviços" ? "serviço" : "produto"} encontrado.</div> :
            filtered.map((i) => <button key={i.id} onClick={() => add(i)} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "12px 14px", borderRadius: 12, border: `1px solid ${t.border}`, background: t.card, boxShadow: "0 1px 4px rgba(24,32,53,0.06)", cursor: "pointer", fontFamily: FONT, transition: "box-shadow .15s" }} onMouseEnter={(e) => (e.currentTarget.style.boxShadow = "0 4px 14px rgba(24,32,53,0.12)")} onMouseLeave={(e) => (e.currentTarget.style.boxShadow = "0 1px 4px rgba(24,32,53,0.06)")}><span style={{ fontSize: 13.5, fontWeight: 600, color: t.text }}>{i.name}</span><span style={{ fontSize: 13, fontWeight: 600, color: t.sage }}>{brl(i.price)}</span></button>)}
        </div>
      </div>
      <div style={{ border: `1px solid ${t.border}`, borderRadius: 14, padding: 18, background: t.card, boxShadow: "0 1px 4px rgba(24,32,53,0.06)", display: "flex", flexDirection: "column", height: "fit-content" }}>
        <Field label="Profissional (opcional)"><Select value={proId} onChange={(e) => setProId(e.target.value)}><option value="">Selecione</option>{professionals.map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}</Select></Field>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 7 }}><label style={{ fontSize: 13, fontWeight: 600, color: t.text }}>Cliente (opcional)</label><button onClick={() => openModal("client")} style={{ display: "inline-flex", alignItems: "center", gap: 4, background: "none", border: "none", color: t.sage, fontSize: 12.5, fontWeight: 600, cursor: "pointer", fontFamily: FONT }}><Plus size={12} /> Novo</button></div>
        <Select value={cliId} onChange={(e) => setCliId(e.target.value)} style={{ marginBottom: 14 }}><option value="">Selecione</option>{clients.map((c) => <option key={c.id} value={c.id}>{c.name}</option>)}</Select>
        <div style={{ flex: 1, minHeight: 90, marginBottom: 12 }}>
          {cart.length === 0 ? <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, padding: "24px 0", color: t.textSec }}><ShoppingCart size={26} /><div style={{ fontSize: 13, fontWeight: 600 }}>Carrinho vazio</div><div style={{ fontSize: 12 }}>Selecione itens ao lado</div></div> :
            cart.map((c) => <div key={c.id} style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 0", borderBottom: `1px solid ${t.border}` }}><div style={{ flex: 1 }}><div style={{ fontSize: 13, fontWeight: 600, color: t.text }}>{c.name}</div><div style={{ fontSize: 12, color: t.textSec }}>{c.qty}× {brl(c.price)}</div></div><span style={{ fontSize: 13, fontWeight: 600, color: t.text }}>{brl(c.price * c.qty)}</span><button onClick={() => setCart((x) => x.filter((y) => y.id !== c.id))} style={{ background: "none", border: "none", cursor: "pointer", color: t.textSec }}><Trash2 size={14} /></button></div>)}
        </div>
        <Field label="Desconto R$"><Input type="number" value={discount} onChange={(e) => setDiscount(e.target.value)} placeholder="0,00" /></Field>
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13, color: t.textSec, marginBottom: 4 }}><span>Subtotal ({cart.length} itens)</span><span>{brl(subtotal)}</span></div>
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 15, fontWeight: 700, color: t.text, marginBottom: 12 }}><span>Total</span><span style={{ color: t.sage }}>{brl(total)}</span></div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 14 }}>{pays.map((m) => <button key={m} onClick={() => setPay(m)} style={{ padding: "7px 10px", borderRadius: 9, border: `1px solid ${pay === m ? t.sage : t.border}`, background: pay === m ? t.sageSoft : "transparent", color: pay === m ? t.sage : t.textSec, fontSize: 11.5, fontWeight: 600, cursor: "pointer", fontFamily: FONT }}>{m}</button>)}</div>
        <PrimaryBtn full disabled={!cart.length} onClick={finalize}><DollarSign size={16} /> Finalizar Venda — {brl(total)}</PrimaryBtn>
      </div>
    </div>
  </Modal>;
}

