function RenewGate({ onLogout }) {
  const t = useT(); const toast = useToast(); const { settings, setSettings, addInvoice } = useData();
  const pl = settings.plan || {}; const [open, setOpen] = useState(false); const wasTrial = !pl.price;
  return <div style={{ minHeight: "100vh", background: t.bg, display: "flex", alignItems: "center", justifyContent: "center", padding: 24, fontFamily: FONT }}>
    <Card style={{ padding: 34, maxWidth: 460, textAlign: "center" }}>
      <div style={{ marginBottom: 18, display: "flex", justifyContent: "center" }}><Logo size={24} /></div>
      <div style={{ width: 60, height: 60, borderRadius: 999, background: "rgba(239,68,68,.1)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px" }}><Lock size={26} color={PALETTE.error} /></div>
      <h1 style={{ fontSize: 21, fontWeight: 800, color: t.text, margin: "0 0 8px" }}>{wasTrial ? "Seu período de teste acabou" : "Sua assinatura expirou"}</h1>
      <p style={{ fontSize: 14, color: t.textSec, lineHeight: 1.6, margin: "0 0 22px" }}>O acesso à Bloomio está pausado desde {fmtBR(pl.expires)}. Assine para voltar a usar tudo de onde parou — <b style={{ color: t.text }}>seus dados continuam salvos</b>.</p>
      <PrimaryBtn full onClick={() => setOpen(true)} style={{ padding: "13px 0", fontSize: 15 }}><Crown size={16} /> {wasTrial ? "Assinar agora" : "Renovar assinatura"}</PrimaryBtn>
      <button onClick={onLogout} style={{ marginTop: 14, background: "none", border: "none", color: t.textSec, fontSize: 13.5, cursor: "pointer", fontFamily: FONT }}>Sair</button>
    </Card>
    <PlanoModal open={open} onClose={() => setOpen(false)} current={pl} onApply={(p) => { setSettings((s) => ({ ...s, plan: { ...s.plan, name: p.name, price: p.price, status: "Ativo", autoRenew: true, startedAt: today(), expires: isoPlus(30) } })); const est = settings.establishment || {}; const num = "BLM-" + (new Date().getFullYear()) + "-" + String(Math.floor(Math.random() * 90000) + 10000); addInvoice({ num, date: today(), plan: p.name, amount: p.price, status: "Pago" }); printDoc("Fatura Bloomio " + num, bloomioInvoiceBody({ num, estName: est.name, estCnpj: est.cnpj, planName: p.name, price: p.price, date: today() }), `Fatura ${num}`, bloomioHead()); toast("Assinatura ativada! Bem-vinda de volta. 🎉"); }} />
  </div>;
}
