  const compartilhar = () => { const ok = copyText(fullUrl); toast(ok ? "Link copiado! Cole onde quiser compartilhar." : "Não foi possível copiar."); try { if (navigator.share) navigator.share({ title: cfg.texts.name, text: "Agende seu horário online", url: fullUrl }).catch(() => {}); } catch (e) {} };
