          <input value={slug} onChange={(e) => setSlug(e.target.value)} style={{ flex: 1, minWidth: 80, border: "none", outline: "none", background: "transparent", padding: "10px 12px 10px 0", fontSize: 13, fontWeight: 600, color: t.sage, fontFamily: FONT }} />
